import type { SSOAccessEnvType, SSOLanguage, SSOSameSiteType, SSOWorkModel, SSOErrorCode, SSOSecondFactorEnum, SSOPromptEnum, SSOIgnoreSLOType } from './config/const';
/**
 * SSO登录配置
 */
export interface SSOLoginConfig {
    /**
     * /应用ID
     */
    readonly clientId: string;
    /**
     * 访问环境，必须设置，否则默认test
     */
    readonly accessEnv: SSOAccessEnvType;
    /**
     * 支持lax、strict、none、不设置四种情况，分别对应strict、lax、none、浏览器默认逻辑
     */
    readonly sameSite?: SSOSameSiteType;
    /**
     * 输出调试信息，默认为false
     */
    readonly isDebug?: boolean;
    /**
     * 工作模式（默认浏览器模式）
     */
    readonly mode: SSOWorkModel;
    /**
     * 登录页面显示语言
     */
    readonly locale?: SSOLanguage & string;
    /**
     * 本地端口号列表（仅限CLI工作模式），如不设置默认为9152
     */
    readonly localPortList?: number[];
    /**
     * SSO Token存储器
     */
    readonly tokenStorage?: SSOTokenStorageInterface;
    /**
     * 泳道环境（仅限accessEnv=test时）
     */
    readonly swimlane?: string;
    /**
     * 指定二次验证类型列表
     *
     * 注：与maxAge参数要求同时传、且参数合法时，才生效。
     */
    readonly secondFactorList?: SSOSecondFactorEnum[];
    /**
     * 指定二次认证间隔时间（单位秒）
     * 注：与secondFactorList参数要求同时传、且参数合法时，才生效。
     *
     * 同一根票下，当前时间 - 用户上次完成二次认证的时间 > max_age时，会要求执行二次认证
     */
    readonly maxAge?: number;
    /**
     * 指定Prompt类型，目前仅支持consent
     */
    readonly prompt?: SSOPromptEnum;
    /**
     * 登录超时时间（单位：秒）
     */
    readonly loginTimeout?: number;
    /**
     * 忽略单点登出类型
     * 场景说明：用户获取应用B的小票时，指定ignoreSLOType = xxx、与应用A共用同一张根票，如果用户退出应用A
     */
    readonly ignoreSLOType?: SSOIgnoreSLOType;
}
/**
 * 用户信息Type
 */
export interface SSOUserInfoType {
    /**
     * mis号
     */
    subject: string;
    /**
     * 姓名
     */
    name: string;
    /**
     * 用户uid，等价于ORG的empid，用户不可变的唯一标识，下游如果落库标识用户，请使用该字段
     */
    mtEmpId: string;
    mtSubjectType?: string;
}
export interface SSOReturnType<T = unknown> {
    /**
     * 操作状态码，0为成功
     */
    code: SSOErrorCode;
    /**
     * 返回数据
     */
    data?: T;
    /**
     * 错误信息
     */
    msg?: string;
}
/**
 * 基础request方法Type
 */
export type RequestType = typeof fetch;
/**
 * code交换Token参数
 */
export interface SSOExchangeTokenByCodeParams {
    code?: string | null;
    state?: string | null;
    codeVerifier?: string;
    clientId?: string;
    sameSite?: SSOSameSiteType;
}
/**
 * SSO token信息
 */
export interface SSOTokenInfoType {
    /**
     * AccessToken
     */
    access_token?: string;
    /**
     * RefreshToken
     */
    refresh_token?: string;
    /**
     * 换票证明
     */
    token_exchange_attestation?: string;
    /**
     * 更新时间
     */
    modified_at?: number;
}
/**
 * SSO token存储器接口，需要使用方实现该接口
 */
export interface SSOTokenStorageInterface {
    /**
     * 获取SSO token信息
     */
    get(): Promise<SSOTokenInfoType>;
    /**
     * 设置SSO token信息
     */
    set(token: SSOTokenInfoType): Promise<void>;
}
/**
 * 日志输出器接口
 */
export interface SSOLogOutputInterface {
    log(...args: unknown[]): void;
    destroy?(): void;
}
